/**
 * Skill 安装 API
 *
 * POST /api/skills/[id]/install
 *
 * 将 Skill 写入 ~/.claude/skills/<name>/SKILL.md 并标记为 installed
 */

import { NextResponse } from "next/server";
import { getDb } from "@/lib/db";
import { expandHome } from "@/lib/project-locator";
import * as fs from "fs";
import * as path from "path";

interface SkillRow {
  id: number;
  name: string;
  markdown: string;
  status: string;
  file_path: string | null;
  scripts?: string;
}

export async function POST(
  _request: Request,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const id = parseInt((await params).id, 10);
    if (isNaN(id)) {
      return NextResponse.json({ success: false, error: "无效的 Skill ID" }, { status: 400 });
    }

    const db = getDb();
    const skill = db.prepare("SELECT * FROM skills WHERE id = ?").get(id) as SkillRow | undefined;

    if (!skill) {
      return NextResponse.json({ success: false, error: "Skill 不存在" }, { status: 404 });
    }

    if (!skill.markdown?.trim()) {
      return NextResponse.json({ success: false, error: "Skill 内容为空" }, { status: 400 });
    }

    // 构建目标路径
    const targetDir = expandHome(path.join("~", ".claude", "skills", skill.name));
    const targetFile = path.join(targetDir, "SKILL.md");

    // 安全检查
    const skillsRoot = expandHome(path.join("~", ".claude", "skills"));
    if (!targetDir.startsWith(skillsRoot)) {
      return NextResponse.json({ success: false, error: "路径不安全" }, { status: 403 });
    }

    // 创建目录 + 写入 SKILL.md
    fs.mkdirSync(targetDir, { recursive: true });
    fs.writeFileSync(targetFile, skill.markdown, "utf-8");

    // 写入 scripts 目录下的配套文件
    const scriptsStr = skill.scripts;
    if (scriptsStr && typeof scriptsStr === "string") {
      try {
        const scripts = JSON.parse(scriptsStr) as Record<string, string>;
        for (const [filePath, fileContent] of Object.entries(scripts)) {
          if (!fileContent || typeof fileContent !== "string") continue;
          const fullPath = path.join(targetDir, filePath);
          const parentDir = path.dirname(fullPath);
          // 安全检查
          if (!fullPath.startsWith(targetDir)) continue;
          fs.mkdirSync(parentDir, { recursive: true });
          fs.writeFileSync(fullPath, fileContent, "utf-8");
        }
      } catch { /* scripts 解析失败，只写 SKILL.md */ }
    }

    // 更新状态
    const now = new Date().toISOString();
    db.prepare(
      "UPDATE skills SET status = 'installed', file_path = ?, updated_at = ? WHERE id = ?"
    ).run(targetFile, now, id);

    return NextResponse.json({
      success: true,
      filePath: targetFile,
      message: `Skill "${skill.name}" 已安装到 ${targetFile}`,
    });
  } catch (err) {
    return NextResponse.json(
      { success: false, error: "安装失败: " + (err instanceof Error ? err.message : String(err)) },
      { status: 500 }
    );
  }
}

import Database from "better-sqlite3";
import path from "path";

// 数据库文件存放路径
const DB_PATH = path.join(process.cwd(), "data", "sessions.db");

let db: Database.Database | null = null;

/**
 * 获取数据库单例连接
 * 首次调用时自动初始化表结构和索引
 */
export function getDb(): Database.Database {
  if (db) return db;

  // 连接数据库（文件不存在时自动创建）
  db = new Database(DB_PATH);

  // 启用 WAL 模式以提升并发读写性能
  db.pragma("journal_mode = WAL");

  // 初始化表结构
  initTables(db);
  // 运行增量迁移
  runMigrations(db);

  return db;
}

/**
 * 创建数据库表和索引
 */
function runMigrations(database: Database.Database): void {
  // skills 表字段迁移
  try {
    const cols = database.prepare("PRAGMA table_info(skills)").all() as Array<{ name: string }>;
    if (!cols.some((c) => c.name === "status")) {
      database.exec("ALTER TABLE skills ADD COLUMN status TEXT DEFAULT 'draft'");
    }
    if (!cols.some((c) => c.name === "scripts")) {
      database.exec("ALTER TABLE skills ADD COLUMN scripts TEXT DEFAULT '{}'");
    }
  } catch {
    // skills 表尚不存在，跳过
  }
}

function initTables(database: Database.Database): void {
  database.exec(`
    -- 会话索引表
    CREATE TABLE IF NOT EXISTS sessions (
      id            TEXT PRIMARY KEY,    -- sessionId (UUID)
      project_slug  TEXT NOT NULL,       -- 项目目录 slug（路径中 / 替换为 -）
      project_path  TEXT NOT NULL,       -- 原始项目路径
      project_name  TEXT,                -- 项目名（取自路径末级）
      first_message TEXT,                -- 首条用户消息（截取前 200 字）
      message_count INTEGER DEFAULT 0,   -- 总消息数
      token_estimate INTEGER DEFAULT 0,  -- 过滤后 Token 估算
      started_at    TEXT,                -- 会话开始时间（ISO 8601）
      updated_at    TEXT,                -- 最后更新时间
      tags          TEXT,                -- 标签（JSON 数组字符串）
      file_path     TEXT NOT NULL,       -- JSONL 文件绝对路径
      file_size     INTEGER,            -- 文件大小（bytes）
      is_deleted    INTEGER DEFAULT 0    -- 软删除标记（0=正常, 1=已删除）
    );

    -- 项目经验 / 开发经验 / 踩坑记录表
    CREATE TABLE IF NOT EXISTS experiences (
      id            INTEGER PRIMARY KEY AUTOINCREMENT,
      type          TEXT NOT NULL,        -- 'project' | 'development' | 'pitfall'
      title         TEXT NOT NULL,
      content       TEXT NOT NULL,        -- JSON 结构（各类型对应不同 schema）
      project_name  TEXT,
      source_ids    TEXT NOT NULL,        -- 来源 sessionId 列表（JSON 数组字符串）
      tags          TEXT,
      created_at    TEXT NOT NULL,
      updated_at    TEXT NOT NULL
    );

    -- Skill 表
    CREATE TABLE IF NOT EXISTS skills (
      id            INTEGER PRIMARY KEY AUTOINCREMENT,
      name          TEXT NOT NULL,        -- Skill 名称（kebab-case）
      description   TEXT NOT NULL,        -- 一句话描述 + 触发条件
      markdown      TEXT NOT NULL,        -- SKILL.md 完整内容
      source_ids    TEXT NOT NULL,        -- 来源 sessionId 列表（JSON 数组字符串）
      status        TEXT DEFAULT 'draft', -- 'draft' | 'ready' | 'installed'
      file_path     TEXT,                 -- 导出/安装文件路径
      created_at    TEXT NOT NULL,
      updated_at    TEXT NOT NULL
    );

    -- 用户配置表
    CREATE TABLE IF NOT EXISTS settings (
      key           TEXT PRIMARY KEY,
      value         TEXT NOT NULL
    );

    -- 提取历史表（记录每个会话每种提取类型的结果，防止重复提取）
    CREATE TABLE IF NOT EXISTS extraction_history (
      id            INTEGER PRIMARY KEY AUTOINCREMENT,
      session_id    TEXT NOT NULL,
      extract_type  TEXT NOT NULL,        -- 'project' | 'development' | 'pitfall' | 'skill'
      status        TEXT NOT NULL,        -- 'success' | 'skipped' | 'error'
      extracted_ids TEXT,                 -- JSON 数组，提取出的经验/Skill id 列表
      summary       TEXT,                 -- 简短摘要
      error_msg     TEXT,                 -- 失败原因（如有）
      created_at    TEXT NOT NULL,
      UNIQUE(session_id, extract_type)    -- 同一会话+类型只保留最新一次记录
    );

    -- 索引：按项目查询会话
    CREATE INDEX IF NOT EXISTS idx_sessions_project ON sessions(project_slug);
    -- 索引：按时间排序会话
    CREATE INDEX IF NOT EXISTS idx_sessions_started ON sessions(started_at DESC);
    -- 索引：按会话查提取历史
    CREATE INDEX IF NOT EXISTS idx_extraction_session ON extraction_history(session_id);
  `);
}

/**
 * 关闭数据库连接（用于测试或进程退出时清理）
 */
export function closeDb(): void {
  if (db) {
    db.close();
    db = null;
  }
}

"use client";

/**
 * Skill 管理页
 *
 * 管理数据库中存储的 Skill（不涉及外部 ~/.claude/skills/ 中非本工具创建的 Skill）。
 * 支持：预览、编辑、导出/安装、卸载、删除。
 *
 * 生命周期：
 *   提取 → draft → 编辑审核 → ready → 安装 → installed
 *                                    └─ 卸载 ─┘
 *                                    └─ 删除 ─→ 删记录（已安装的先卸文件）
 */

import { useState, useEffect, useCallback } from "react";
import Icon from "@/components/Icon";
import type { Skill } from "@/components/SkillCard";
import { SkillEditModal, SkillDeleteConfirm } from "@/components/SkillCard";
import EmptyState from "@/components/EmptyState";

// ─── 状态徽章 ────────────────────────────────────────────

const STATUS_CONFIG: Record<string, { label: string; bg: string }> = {
  draft: { label: "草稿", bg: "bg-gray-100 text-gray-600" },
  ready: { label: "就绪", bg: "bg-[var(--yellow)] text-black" },
  installed: { label: "已安装", bg: "bg-green-100 text-green-700" },
};

// ─── 页面组件 ────────────────────────────────────────────

export default function SkillsPage() {
  const [skills, setSkills] = useState<Skill[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // 操作中状态
  const [installing, setInstalling] = useState<Set<number>>(new Set());
  const [uninstalling, setUninstalling] = useState<Set<number>>(new Set());
  const [optimizingId, setOptimizingId] = useState<number | null>(null);
  const [optimizeInstruction, setOptimizeInstruction] = useState("");

  // 编辑模态框
  const [editingSkill, setEditingSkill] = useState<Skill | null>(null);
  // 删除确认
  const [deletingSkill, setDeletingSkill] = useState<Skill | null>(null);
  const [isDeleting, setIsDeleting] = useState(false);

  // 展开的 Skill ID 集合
  const [expandedIds, setExpandedIds] = useState<Set<number>>(new Set());

  // 通知消息
  const [notification, setNotification] = useState<{ type: "success" | "error"; msg: string } | null>(null);

  /** 获取所有 Skill */
  const fetchSkills = useCallback(async () => {
    try {
      const res = await fetch("/api/skills");
      const data = await res.json();
      if (data.success) {
        setSkills(data.skills as Skill[]);
      } else {
        setError(data.error || "加载失败");
      }
    } catch {
      setError("网络请求失败");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchSkills();
  }, [fetchSkills]);

  /** 安装 Skill */
  async function handleInstall(skill: Skill) {
    setInstalling((prev) => new Set(prev).add(skill.id));
    try {
      const res = await fetch(`/api/skills/${skill.id}/install`, { method: "POST" });
      const data = await res.json();
      if (data.success) {
        setNotification({ type: "success", msg: data.message });
        fetchSkills();
      } else {
        setNotification({ type: "error", msg: data.error });
      }
    } catch {
      setNotification({ type: "error", msg: "安装失败" });
    } finally {
      setInstalling((prev) => { const next = new Set(prev); next.delete(skill.id); return next; });
    }
  }

  /** 卸载 Skill */
  async function handleUninstall(skill: Skill) {
    setUninstalling((prev) => new Set(prev).add(skill.id));
    try {
      const res = await fetch(`/api/skills/${skill.id}/uninstall`, { method: "POST" });
      const data = await res.json();
      if (data.success) {
        setNotification({ type: "success", msg: data.message });
        fetchSkills();
      } else {
        setNotification({ type: "error", msg: data.error });
      }
    } catch {
      setNotification({ type: "error", msg: "卸载失败" });
    } finally {
      setUninstalling((prev) => { const next = new Set(prev); next.delete(skill.id); return next; });
    }
  }

  /** 删除 Skill */
  async function handleOptimize(skill: Skill) {
    if (!optimizeInstruction.trim()) return;
    setOptimizingId(skill.id);
    try {
      const r = await fetch(`/api/skills/${skill.id}/optimize`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ instruction: optimizeInstruction }),
      });
      if (r.ok) { fetchSkills(); setOptimizeInstruction(""); }
    } catch { /* ignore */ }
    setOptimizingId(null);
  }

  async function handleDelete() {
    if (!deletingSkill) return;
    setIsDeleting(true);
    try {
      const res = await fetch(`/api/skills/${deletingSkill.id}`, { method: "DELETE" });
      const data = await res.json();
      if (data.success) {
        setNotification({ type: "success", msg: `"${deletingSkill.name}" 已删除` });
        fetchSkills();
      } else {
        setNotification({ type: "error", msg: data.error });
      }
    } catch {
      setNotification({ type: "error", msg: "删除失败" });
    } finally {
      setIsDeleting(false);
      setDeletingSkill(null);
    }
  }

  /** 编辑保存 */
  function handleSave() {
    fetchSkills();
    setEditingSkill(null);
  }

  /** 通知自动消失 */
  useEffect(() => {
    if (!notification) return;
    const t = setTimeout(() => setNotification(null), 4000);
    return () => clearTimeout(t);
  }, [notification]);

  // ─── 渲染 ────────────────────────────────

  return (
    <div className="p-6 md:p-8">
      {/* 标题 */}
      <div className="mb-6">
        <h2 className="text-2xl font-bold">Skill 管理</h2>
        <p className="text-sm text-gray-800 mt-1">
          管理从会话中提取的 Skill。安装后 Claude Code 自动识别。
        </p>
      </div>

      {/* 通知 */}
      {notification && (
        <div
          className={`nb-border px-4 py-2 mb-4 text-sm font-bold ${
            notification.type === "success" ? "bg-green-100 text-green-800" : "bg-red-100 text-red-700"
          }`}
        >
          <Icon name={notification.type === "success" ? "check" : "close"} size={12} className="mr-1" />
          {notification.msg}
        </div>
      )}

      {/* 加载 / 错误 / 空状态 */}
      {loading && (
        <div className="space-y-3 animate-pulse">
          {[1, 2, 3].map((i) => (
            <div key={i} className="nb-card p-6 h-24 bg-gray-200" />
          ))}
        </div>
      )}

      {error && (
        <div className="nb-card p-8 text-center">
          <div className="text-5xl mb-4 flex justify-center"><Icon name="warning" size={48} /></div>
          <h3 className="text-lg font-bold mb-2">加载失败</h3>
          <p className="text-sm text-gray-800 mb-4">{error}</p>
          <button onClick={fetchSkills} className="nb-button px-6 py-2 text-sm bg-[var(--yellow)]">
            <Icon name="refresh" size={14} className="mr-1" />重试
          </button>
        </div>
      )}

      {!loading && !error && skills.length === 0 && (
        <EmptyState
          icon={null}
          title="还没有 Skill"
          description="从会话中提取重复的操作模式，生成可复用的 Skill。"
        />
      )}

      {/* Skill 列表 */}
      {!loading && !error && skills.length > 0 && (
        <div className="space-y-4">
          {skills.map((skill) => {
            const isExpanded = expandedIds.has(skill.id);
            const statusCfg = STATUS_CONFIG[skill.status] || STATUS_CONFIG.draft;

            return (
              <div key={skill.id} className="nb-card font-mono">
                {/* 卡片头部 */}
                <button
                  onClick={() =>
                    setExpandedIds((prev) => {
                      const next = new Set(prev);
                      if (isExpanded) next.delete(skill.id);
                      else next.add(skill.id);
                      return next;
                    })
                  }
                  className="w-full flex items-center gap-3 px-4 py-3 hover:bg-[var(--gray-100)] transition-colors cursor-pointer text-left"
                >
                  <span
                    className="inline-block transition-transform duration-150 shrink-0"
                    style={{ transform: isExpanded ? "rotate(90deg)" : "rotate(0deg)" }}
                  >
                    <Icon name="chevronRight" size={12} />
                  </span>
                  <span className="flex-1 font-bold text-sm truncate">{skill.name}</span>
                  <span className={`text-[10px] px-2 py-0.5 nb-border font-bold shrink-0 ${statusCfg.bg}`}>
                    {statusCfg.label}
                  </span>
                </button>

                {/* 描述 */}
                <div className="px-4 pb-2">
                  <p className="text-xs text-gray-700 line-clamp-2">
                    {skill.description?.slice(0, 200) || "无描述"}
                  </p>
                </div>

                {/* 展开：markdown 预览 */}
                {isExpanded && (
                  <div className="px-4 pb-3 border-t-2 border-black pt-3">
                    <pre className="text-[10px] text-gray-800 bg-[var(--gray-100)] p-3 max-h-64 overflow-auto whitespace-pre-wrap border border-gray-300">
                      {skill.markdown?.slice(0, 2000)}
                      {(skill.markdown?.length || 0) > 2000 && "\n\n...（完整内容请点击编辑查看）"}
                    </pre>
                    <div className="flex items-center gap-2 mt-2">
                      <input
                        type="text"
                        placeholder="输入优化指令，如：简化表述"
                        value={optimizingId === skill.id ? "" : optimizeInstruction}
                        onChange={(e) => setOptimizeInstruction(e.target.value)}
                        className="nb-input py-1 px-2 text-[10px] flex-1"
                        onKeyDown={(e) => { if (e.key === "Enter") handleOptimize(skill); }}
                      />
                      <button
                        onClick={() => handleOptimize(skill)}
                        disabled={optimizingId === skill.id}
                        className="nb-button px-2 py-1 text-[10px] bg-[var(--yellow)]"
                      >
                        {optimizingId === skill.id ? "..." : "继续优化"}
                      </button>
                    </div>
                    {skill.file_path && (
                      <p className="mt-2 text-[10px] text-gray-500">
                        安装路径：<code className="text-green-700">{skill.file_path}</code>
                      </p>
                    )}
                  </div>
                )}

                {/* 操作按钮 */}
                <div className="flex items-center gap-2 px-4 pb-3 pt-2 border-t-2 border-black">
                  {/* 编辑 */}
                  <button
                    onClick={() => setEditingSkill(skill)}
                    className="nb-button px-3 py-1 text-xs bg-white"
                  >
                    <Icon name="edit" size={12} /> 编辑
                  </button>

                  {/* 安装 / 已安装 */}
                  {skill.status !== "installed" ? (
                    <button
                      onClick={() => handleInstall(skill)}
                      disabled={installing.has(skill.id)}
                      className="nb-button px-3 py-1 text-xs bg-[var(--magenta)] text-white"
                    >
                      <Icon name="package" size={12} />
                      {installing.has(skill.id) ? "安装中..." : "安装"}
                    </button>
                  ) : (
                    <button
                      onClick={() => handleUninstall(skill)}
                      disabled={uninstalling.has(skill.id)}
                      className="nb-button px-3 py-1 text-xs bg-[var(--yellow)] text-black"
                    >
                      <Icon name="refresh" size={12} />
                      {uninstalling.has(skill.id) ? "卸载中..." : "卸载"}
                    </button>
                  )}

                  {/* 删除 */}
                  <button
                    onClick={() => setDeletingSkill(skill)}
                    className="nb-button px-3 py-1 text-xs bg-red-500 text-white ml-auto"
                  >
                    <Icon name="trash" size={12} /> 删除
                  </button>
                </div>
              </div>
            );
          })}
        </div>
      )}

      {/* 编辑模态框 */}
      {editingSkill && (
        <SkillEditModal
          skill={editingSkill}
          isOpen={!!editingSkill}
          onClose={() => setEditingSkill(null)}
          onSave={() => handleSave()}
        />
      )}

      {/* 删除确认 */}
      {deletingSkill && (
        <SkillDeleteConfirm
          skillName={deletingSkill.name}
          isOpen={!!deletingSkill}
          isDeleting={isDeleting}
          onClose={() => setDeletingSkill(null)}
          onConfirm={handleDelete}
        />
      )}
    </div>
  );
}
